import { test, expect } from '@playwright/test';

/**
 * E2E test for factory import functionality
 * 
 * This test verifies that users can:
 * 1. Navigate to the import dialog
 * 2. Paste a compressed factory export string
 * 3. Import multiple factories from the export
 * 4. View and interact with the imported factory nodes
 */
test('import factory from compressed export string', async ({ page }) => {
  // Navigate to default factory view
  await page.goto('./zones/main/default-factory', { waitUntil: 'domcontentloaded' });

  // Open factory menu and navigate to import settings
  await page.getByTestId('zone-sidebar-expand-toggle').click();
  const importLink = page.getByTestId('import-factory-link');
  await importLink.waitFor();
  await importLink.click();
  
  // Switch to Import tab
  await page.getByTestId('settings-tab-import').click();

  // Paste factory export string (contains 2 factories: Nuclear Reactor and Glass Smelting setups)
  const exportString = '';
  await page.getByTestId('import-textarea').fill(exportString);

  // Click import button
  await page.getByTestId('import-factories-button').click();

  // Verify imported nodes are visible in the graph
  // These test IDs are automatically generated by React Flow based on node IDs
  await expect(page.getByTestId('rf__node-NuclearReactorT22_1768051043853')).toBeVisible();
  await expect(page.getByTestId('rf__node-SpentFuelReprocessing_1768051192440')).toBeVisible();

  // Test interaction: click on nodes to select them
  await page.getByTestId('factory-controls-graph-update-button').click();
  await page.getByTestId('rf__node-GlassSmeltingArcT1WithBroken_1769071268468').click();

  // Verify the summary panel shows expected production rates
  // Uses regex for numeric values that may vary slightly
  await expect(page.getByTestId('sidebar-byproducts-list')).toMatchAriaSnapshot(`
    - img
    - text: "7.7"
    - img
    - text: "0.4"
    - img
    - text: "0.4"
    - img
    - text: "27.8"
    - img
    - text: "48.1"
    - img
    - text: "0.1"
  `);
});
